        public void Test_SimpleTable()
        {
            // Simple table with header
            var result = HtmlToMarkdownConverter.Convert("<table><thead><tr><th>Name</th><th>Age</th></tr></thead><tbody><tr><td>Alice</td><td>30</td></tr></tbody></table>", new ConversionOptions());
    Assert.Contains("name", result.Content.ToString().ToLower());
    Assert.Contains("age", result.Content.ToString().ToLower());
    Assert.Contains("alice", result.Content.ToString().ToLower());
    Assert.Contains("30", result.Content.ToString().ToLower());
    Assert.Contains("|", result.Content.ToString().ToLower());
    Assert.Contains("---", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_TableEmpty()
        {
            // Empty table produces no output or minimal output
            var result = HtmlToMarkdownConverter.Convert("<table></table>", new ConversionOptions());
    Assert.Equal("", result.Content!.Trim());

        }

        [Fact]
        public void Test_TableNoThead()
        {
            // Table without thead uses first row as implied header
            var result = HtmlToMarkdownConverter.Convert("<table><tr><td>Product</td><td>Price</td></tr><tr><td>Apple</td><td>1.00</td></tr></table>", new ConversionOptions());
    Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
    Assert.Contains("product", result.Content.ToString().ToLower());
    Assert.Contains("price", result.Content.ToString().ToLower());
    Assert.Contains("apple", result.Content.ToString().ToLower());
    Assert.Contains("1.00", result.Content.ToString().ToLower());
    Assert.Contains("|", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_TablePipeCharsInContent()
        {
            // Table cells containing pipe characters are escaped in output
            var result = HtmlToMarkdownConverter.Convert("<table><thead><tr><th>Expression</th><th>Result</th></tr></thead><tbody><tr><td>a | b</td><td>true</td></tr></tbody></table>", new ConversionOptions());
    Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
    Assert.Contains("expression", result.Content.ToString().ToLower());
    Assert.Contains("result", result.Content.ToString().ToLower());
    Assert.Contains("true", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_TableWithAlignment()
        {
            // Table with column alignment attributes
            var result = HtmlToMarkdownConverter.Convert("<table><thead><tr><th align=\"left\">Left</th><th align=\"center\">Center</th><th align=\"right\">Right</th></tr></thead><tbody><tr><td>L</td><td>C</td><td>R</td></tr></tbody></table>", new ConversionOptions());
    Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
    Assert.Contains("left", result.Content.ToString().ToLower());
    Assert.Contains("center", result.Content.ToString().ToLower());
    Assert.Contains("right", result.Content.ToString().ToLower());
    Assert.Contains("l", result.Content.ToString().ToLower());
    Assert.Contains("c", result.Content.ToString().ToLower());
    Assert.Contains("r", result.Content.ToString().ToLower());
    Assert.Contains("|", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_TableWithColspan()
        {
            // Table with colspan attribute in a header cell
            var result = HtmlToMarkdownConverter.Convert("<table><thead><tr><th colspan=\"2\">Full Name</th></tr></thead><tbody><tr><td>John</td><td>Doe</td></tr></tbody></table>", new ConversionOptions());
    Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
    Assert.Contains("full name", result.Content.ToString().ToLower());
    Assert.Contains("john", result.Content.ToString().ToLower());
    Assert.Contains("doe", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_UnorderedList()
        {
            // Unordered list
            var result = HtmlToMarkdownConverter.Convert("<ul><li>Item 1</li><li>Item 2</li><li>Item 3</li></ul>", new ConversionOptions());
    Assert.Contains("- item 1", result.Content.ToString().ToLower());
    Assert.Contains("- item 2", result.Content.ToString().ToLower());
    Assert.Contains("- item 3", result.Content.ToString().ToLower());

        }


